codeExamples.code:
SELECT region, SUM(amount) AS total_sales
FROM sales
GROUP BY region;

commonMistakes.wrongCode:
SELECT region, salesperson, SUM(amount)
FROM sales
GROUP BY region;

commonMistakes.correctCode:
-- If you want per-region, drop salesperson:
SELECT region, SUM(amount) FROM sales GROUP BY region;

-- If you want per-(region, salesperson), include both:
SELECT region, salesperson, SUM(amount) FROM sales GROUP BY region, salesperson;

codingChallenges.solution:
SELECT region, SUM(amount) AS total, COUNT(*) AS sales_count, AVG(amount) AS avg_sale
FROM sales
GROUP BY region;
